        super._beforeTokenTransfer(from, to, amount);
    }

    function burn(uint256 amount) public {
        _burn(msg.sender, amount);
    }

    function setSecurityProxy(address _securityProxy) external {
        onlyRealmGuardian();
        securityProxy = _securityProxy;
    }

}

